spec.expr:
sum by (path, status) (
  count_over_time(
    {container=~"$service_name"} 
    | json status="context.status_code", path="context.path", type="context.type"
    | type = "response"
    | status =~ "2.." 
    [$__interval]
  )
)

{service_name="$service_name"} 
| json req_id="context.request_id", ua="context.user_agent", method="context.method", path="context.path", delay="context.delay_num", message="message"
| line_format "{{if .req_id}}{{.req_id}} |{{end}} {{.message}} {{if .ua}}| UA: {{.ua}}{{end}} {{if .delay}}| {{.delay}}ms {{end}}"

avg by (method, path) (
  avg_over_time(
    {container=~"$service_name"} 
    | json delay="context.delay_num", path="context.path", method="context.method"
    | delay != ""
    | unwrap delay [$__range]
  )
)

sum by (path) (
  rate(
    {container=~"$service_name"} | json | context_type = "request" | label_format path="{{.context_path}}" [$__interval]
  )
)

sum by (path) (
  rate(
    {container=~"$service_name"} 
    | json path="context.path", type="context.type"
    | __error__="" 
    | type = "request"
    [$__interval]
  )
)

sum by (path) (
  rate(
    {container=~"$service_name"} 
    | json path="path=context.path", status="context.status_code", type="context.type"
    | __error__="" 
    | type = "response"
    | status !~ "2.." 
    [$__interval]
  )
)

sum by (path) (
  avg_over_time(
    {container=~"$service_name"} 
    | json delay="context.delay_num", path="context.path", type="context.type"
    | type = "response"
    | unwrap delay 
    | delay > 500
    [$__interval]
  )
)
